+	if err != nil {
+		return caps, nil
+	}
+
+	// bv 0.30+ has robot-triage
+	if version.AtLeast(Version{Major: 0, Minor: 30, Patch: 0}) {
+		caps = append(caps, "robot_triage", "robot_plan", "robot_insights")
